// ============================================================
// SENTINEL FORENSIC PARSE ENGINE v3 — FIXED
// Handles: multipart file upload OR JSON records body
// Fixes: UUID generation, lat/long 3-token parsing, IMEI mapping,
//        comm_links, tower_analysis, common_numbers, anomalies
// ============================================================

const body = $('Forensic Webhook').first().json.body || {};

function makeShortId() {
  return Math.random().toString(36).substring(2, 9).toUpperCase();
}
function makeUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const investigationId = body.investigation_id || ('INV-' + makeShortId());
const investigationUUID = makeUUID(); // always a real UUID for Supabase PK

// ── Collect raw rows ─────────────────────────────────────────
let rawRecords = [];

// Path 1: JSON records array in body
if (body.records && Array.isArray(body.records) && body.records.length > 0) {
  rawRecords = body.records;
}
// Path 2: rows parsed upstream by a spreadsheet node (passed as items)
else {
  const items = $input.all();
  if (items.length > 1 || (items.length === 1 && items[0].json && Object.keys(items[0].json).length > 5)) {
    rawRecords = items.map(i => i.json);
  }
}

if (rawRecords.length === 0) {
  // Return a structured empty response so frontend doesn't crash
  return [{
    json: {
      success: false,
      error: 'No records found. Ensure the Excel/CSV file was uploaded correctly and contains data rows.',
      investigation_id: investigationId,
      investigation_uuid: investigationUUID,
      records_json: [],
      timeline_json: [],
      geo_json: [],
      comm_links: [],
      tower_analysis: [],
      common_numbers: [],
      imei_mapping: [],
      anomalies: [],
      ai_context: '{}',
      risk_index: 0,
      total_records: 0,
      anomaly_count: 0
    }
  }];
}

// ── Parse & Score ─────────────────────────────────────────────
const scored = rawRecords.map((rec, idx) => {
  let risk = 0;

  // Timestamp
  const dateStr = String(rec.Date || rec.date || rec.timestamp || rec['Call Date'] || '');
  const timeStr = String(rec.Time || rec.time || rec['Call Time'] || '');
  let ts = new Date().toISOString();
  if (dateStr && dateStr !== 'undefined') {
    try {
      ts = new Date(timeStr ? `${dateStr} ${timeStr}` : dateStr).toISOString();
      if (isNaN(new Date(ts).getTime())) ts = new Date().toISOString();
    } catch(e) { ts = new Date().toISOString(); }
  }
  const hour = new Date(ts).getHours();
  if (hour >= 0 && hour <= 5) risk += 20;

  // Duration
  const duration = parseInt(rec.Duration || rec.duration || rec['Call Duration'] || 0) || 0;
  if (duration > 300) risk += 15;
  if (duration > 600) risk += 10;

  // Call type
  const callType = String(rec['Call Type'] || rec.call_type || rec.Type || 'CALL').toUpperCase();

  // ── Lat/Long parsing — handles 3-token format "lat long azimuth" ──
  let latitude = 0;
  let longitude = 0;

  if (rec.Latitude && rec.Longitude) {
    latitude = parseFloat(rec.Latitude) || 0;
    longitude = parseFloat(rec.Longitude) || 0;
  } else {
    // Try multiple possible column names for Indian CDR formats
    const geoRaw = String(
      rec['Lat-Long-Azimuth (First CellID)'] ||
      rec['Lat Long Azimuth (First CellID)'] ||
      rec['LatLongAzimuth'] ||
      rec['Lat-Long'] ||
      rec['Location'] ||
      rec['lat_long'] ||
      ''
    ).trim();

    if (geoRaw) {
      // Split on whitespace or comma
      const tokens = geoRaw.split(/[\s,]+/).filter(t => t.length > 0);
      if (tokens.length >= 2) {
        const lat = parseFloat(tokens[0]);
        const lng = parseFloat(tokens[1]);
        // Sanity check: valid India coordinates roughly 8–37 lat, 68–97 long
        if (!isNaN(lat) && !isNaN(lng) && lat > 5 && lat < 40 && lng > 60 && lng < 100) {
          latitude = lat;
          longitude = lng;
        }
      }
    }
  }

  // IMEI
  const imei = String(rec.IMEI || rec.imei || rec['Device IMEI'] || '').trim();

  // A-party / B-party
  const aParty = String(rec.CdrNo || rec.a_party || rec['A Party'] || rec['A-Party'] || rec.Caller || '').trim();
  const bParty = String(rec['B Party'] || rec.b_party || rec['B-Party'] || rec.Receiver || rec.Called || '').trim();

  // Tower
  const towerId = String(rec['First Cell ID'] || rec['Cell ID'] || rec.tower_id || rec['CellID'] || rec['Cell Id'] || '').trim();
  const towerAddress = String(rec['First Cell ID Address'] || rec['Tower Address'] || rec['Cell Address'] || '').trim();

  return {
    s_no: idx + 1,
    a_party: aParty,
    b_party: bParty,
    timestamp: ts,
    duration,
    tower_id: towerId,
    tower_address: towerAddress,
    latitude,
    longitude,
    imei,
    call_type: callType,
    risk_score: Math.min(risk, 100)
  };
});

// ── Derived datasets ─────────────────────────────────────────
const totalRisk = scored.length > 0
  ? Math.round(scored.reduce((a, b) => a + b.risk_score, 0) / scored.length)
  : 0;

// geo_json: only records with valid coordinates
const geo_json = scored.filter(r => r.latitude !== 0 && r.longitude !== 0).map(r => ({
  lat: r.latitude,
  lng: r.longitude,
  tower: r.tower_id,
  address: r.tower_address,
  a_party: r.a_party,
  ts: r.timestamp
}));

// timeline_json
const timeline_json = [...scored].sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

// comm_links
const linkMap = {};
scored.forEach(r => {
  if (r.a_party && r.b_party) {
    const key = [r.a_party, r.b_party].sort().join('|||');
    linkMap[key] = (linkMap[key] || 0) + 1;
  }
});
const comm_links = Object.entries(linkMap).map(([k, count]) => {
  const [src, tgt] = k.split('|||');
  return { source: src, target: tgt, weight: count };
});

// tower_analysis
const towerMap = {};
scored.forEach(r => {
  if (r.tower_id) {
    if (!towerMap[r.tower_id]) towerMap[r.tower_id] = { hits: 0, address: r.tower_address };
    towerMap[r.tower_id].hits++;
  }
});
const tower_analysis = Object.entries(towerMap)
  .map(([id, v]) => ({ tower_id: id, hits: v.hits, address: v.address }))
  .sort((a, b) => b.hits - a.hits);

// common_numbers
const numMap = {};
scored.forEach(r => { if (r.b_party) numMap[r.b_party] = (numMap[r.b_party] || 0) + 1; });
const common_numbers = Object.entries(numMap)
  .map(([num, count]) => ({ number: num, contact_count: count }))
  .sort((a, b) => b.contact_count - a.contact_count)
  .slice(0, 30);

// imei_mapping
const imeiMap = {};
scored.forEach(r => {
  if (r.imei) {
    if (!imeiMap[r.imei]) imeiMap[r.imei] = new Set();
    if (r.a_party) imeiMap[r.imei].add(r.a_party);
  }
});
const imei_mapping = Object.entries(imeiMap).map(([imei, nums]) => ({
  imei,
  msisdns: [...nums],
  msisdn_count: nums.size
}));

// anomalies
const anomalies = scored.filter(r => r.risk_score > 10);

// ai_context — compact summary for Gemini
const ai_context = JSON.stringify({
  total_records: scored.length,
  risk_index: totalRisk,
  anomaly_count: anomalies.length,
  geo_points: geo_json.length,
  top_towers: tower_analysis.slice(0, 8),
  top_contacts: common_numbers.slice(0, 10),
  imei_count: imei_mapping.length,
  imei_summary: imei_mapping.slice(0, 5),
  date_range: {
    start: timeline_json[0]?.timestamp || null,
    end: timeline_json[timeline_json.length - 1]?.timestamp || null
  },
  sample_records: scored.slice(0, 20)
});

return [{
  json: {
    success: true,
    investigation_id: investigationId,
    investigation_uuid: investigationUUID,
    case_number: 'CASE-' + investigationId,
    title: body.title || body.filename || 'CDR Forensic Analysis',
    records_json: scored,
    timeline_json,
    geo_json,
    comm_links,
    tower_analysis,
    common_numbers,
    imei_mapping,
    anomalies,
    ai_context,
    risk_index: totalRisk,
    total_records: scored.length,
    anomaly_count: anomalies.length
  }
}];

// Unwrap the Supabase array response and parse all JSON fields
const rows = $input.first().json;
const row = Array.isArray(rows) ? rows[0] : rows;

if (!row) {
  return [{ json: { error: 'Investigation not found in database', row: null } }];
}

// Parse all stringified JSON fields back to objects
function safeJSON(val) {
  if (!val) return [];
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch(e) { return []; }
}

const records_json = safeJSON(row.records_json);
const timeline_json = safeJSON(row.timeline_json);
const geo_json = safeJSON(row.geo_json);
const analysis = safeJSON(row.analysis_json);
const metadata = safeJSON(row.metadata);
let ai_context = {};
try { ai_context = JSON.parse(row.ai_context || '{}'); } catch(e) {}

return [{
  json: {
    investigation_id: metadata.investigation_id || row.case_number,
    case_number: row.case_number,
    title: row.title,
    total_records: row.total_records,
    risk_index: row.risk_score,
    anomaly_count: metadata.anomaly_count || 0,
    records_json,
    timeline_json,
    geo_json,
    comm_links: analysis.comm_links || [],
    tower_analysis: analysis.tower_analysis || [],
    common_numbers: analysis.common_numbers || [],
    imei_mapping: analysis.imei_mapping || [],
    anomalies: metadata.anomalies || [],
    ai_context,
    // Pass the user's question from the original request
    user_message: $('Forensic Webhook').first().json.body.message || 'Provide a summary of this investigation.'
  }
}];

options.systemMessage:
